#include <stdio.h>
#include <stdlib.h>

long long maxRectangle(int *h, int n) {
    int *stack = (int*)malloc(n * sizeof(int));
    int top = -1;
    long long maxArea = 0;
    for (int i = 0; i < n; ++i) {
        while (top >= 0 && h[stack[top]] > h[i]) {
            int height = h[stack[top--]];
            int width = (top == -1) ? i : i - stack[top] - 1;
            long long area = (long long)height * width;
            if (area > maxArea) maxArea = area;
        }
        stack[++top] = i;
    }
    while (top >= 0) {
        int height = h[stack[top--]];
        int width = (top == -1) ? n : n - stack[top] - 1;
        long long area = (long long)height * width;
        if (area > maxArea) maxArea = area;
    }
    free(stack);
    return maxArea;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        printf("%lld\n", maxRectangle(arr, N));
        free(arr);
    }
    return 0;
}

