long long largestRectangle(const vector<long long>& h) {
    int n = h.size();
    vector<int> st;
    long long ans = 0;
    for (int i = 0; i < n; ++i) {
        while (!st.empty() && h[st.back()] > h[i]) {
            long long height = h[st.back()];
            st.pop_back();
            int left = st.empty() ? -1 : st.back();
            long long width = i - left - 1;
            ans = max(ans, height * width);
        }
        st.push_back(i);
    }
    while (!st.empty()) {
        long long height = h[st.back()];
        st.pop_back();
        int left = st.empty() ? -1 : st.back();
        long long width = n - left - 1;
        ans = max(ans, height * width);
    }
    return ans;
